package meters

import (
	"context"
	"net/http"

	api "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/openmeter/meter"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/models"
)

type (
	CloneMeterRequest struct {
		models.NamespacedID
		Name string
	}
	CloneMeterResponse = api.Meter
	CloneMeterParams   = string
	CloneMeterHandler  httptransport.HandlerWithArgs[CloneMeterRequest, CloneMeterResponse, CloneMeterParams]
)

func (h *handler) CloneMeter() CloneMeterHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, meterID CloneMeterParams) (CloneMeterRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return CloneMeterRequest{}, err
			}
			return CloneMeterRequest{
				NamespacedID: models.NamespacedID{Namespace: ns, ID: meterID},
				Name:         r.URL.Query().Get("name"),
			}, nil
		},
		func(ctx context.Context, req CloneMeterRequest) (CloneMeterResponse, error) {
			m, err := h.service.CloneMeter(ctx, meter.CloneMeterInput{NamespacedID: req.NamespacedID, Name: req.Name})
			if err != nil {
				return CloneMeterResponse{}, err
			}
			return ToAPIMeter(m), nil
		},
		commonhttp.JSONResponseEncoderWithStatus[CloneMeterResponse](http.StatusCreated),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("clone-meter"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}

