package plans

import (
	"context"
	"fmt"
	"net/http"

	api "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/openmeter/productcatalog/plan"
	"github.com/openmeterio/openmeter/pkg/clock"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/models"
)

type (
	ClonePlanRequest  = plan.ClonePlanInput
	ClonePlanResponse = api.BillingPlan
	ClonePlanParams   = string
	ClonePlanHandler  httptransport.HandlerWithArgs[ClonePlanRequest, ClonePlanResponse, ClonePlanParams]
)

func (h *handler) ClonePlan() ClonePlanHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, planID ClonePlanParams) (ClonePlanRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return ClonePlanRequest{}, err
			}
			return ClonePlanRequest{
				NamespacedID: models.NamespacedID{Namespace: ns, ID: planID},
				ClonedAt:     clock.Now(),
			}, nil
		},
		func(ctx context.Context, request ClonePlanRequest) (ClonePlanResponse, error) {
			p, err := h.service.ClonePlan(ctx, request)
			if err != nil {
				return ClonePlanResponse{}, err
			}
			if p == nil {
				return ClonePlanResponse{}, fmt.Errorf("failed to clone plan")
			}
			return ToAPIBillingPlan(*p)
		},
		commonhttp.JSONResponseEncoderWithStatus[ClonePlanResponse](http.StatusCreated),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("clone-plan"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}

