package subscriptions

import (
	"context"
	"net/http"

	api "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/api/v3/request"
	"github.com/openmeterio/openmeter/openmeter/subscription"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	models "github.com/openmeterio/openmeter/pkg/models"
)

type (
	PauseSubscriptionRequest struct {
		ID     models.NamespacedID
		Timing subscription.Timing
	}
	PauseSubscriptionResponse = api.BillingSubscription
	PauseSubscriptionParams   = string
	PauseSubscriptionHandler  httptransport.HandlerWithArgs[PauseSubscriptionRequest, PauseSubscriptionResponse, PauseSubscriptionParams]
)

func (h *handler) PauseSubscription() PauseSubscriptionHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, subID PauseSubscriptionParams) (PauseSubscriptionRequest, error) {
			body := api.BillingSubscriptionPause{}
			if err := request.ParseBody(r, &body); err != nil {
				return PauseSubscriptionRequest{}, err
			}
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return PauseSubscriptionRequest{}, err
			}
			timing, err := FromAPIBillingSubscriptionEditTiming(body.Timing)
			if err != nil {
				return PauseSubscriptionRequest{}, err
			}
			return PauseSubscriptionRequest{
				ID:     models.NamespacedID{Namespace: ns, ID: subID},
				Timing: timing,
			}, nil
		},
		func(ctx context.Context, req PauseSubscriptionRequest) (PauseSubscriptionResponse, error) {
			sub, err := h.subscriptionService.Pause(ctx, req.ID, req.Timing)
			if err != nil {
				return PauseSubscriptionResponse{}, err
			}
			return ToAPIBillingSubscription(sub), nil
		},
		commonhttp.JSONResponseEncoderWithStatus[PauseSubscriptionResponse](http.StatusOK),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("pause-subscription"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}
